#include<bits/stdc++.h>
using namespace std;
int main() 
{
	int x,y,z,n,m,k,map=0;
	cin>>x>>y>>z>>n>>m;
	for(int i=1;i<=m/5;i++)
	{
		for(int j=1;j<=m/3;j++)
		{
			k=m-i-j;
			if(i*5+j*3+k*1.0/3==n)
			{
				map++;
			}
		} 
	} 
	cout<<map;
	return 0; 
}
